1	import { useEffect, useMemo, useRef, useState } from 'react';
2	
3	import { fetchSectionProjectionWire } from '../plan/sectionProjectionWire';
4	import {
5	  SECTION_VIEWPORT_ADVISORY_MAX_CHARS,
6	  SECTION_VIEWPORT_LABEL_FONT_MAX_PX,
7	  SECTION_VIEWPORT_LABEL_FONT_MIN_PX,
8	  SECTION_VIEWPORT_LEVEL_SPAN_BRACKET_MARGIN_PX,
9	  SECTION_VIEWPORT_LEVEL_SPAN_LABEL_MIN_PX,
10	  SECTION_VIEWPORT_MATERIAL_HINT_MIN_VIEW_PX,
11	  SECTION_VIEWPORT_OPENING_TAG_MIN_PX,
12	  SECTION_VIEWPORT_SCALE_BASELINE_PX,
13	  SECTION_VIEWPORT_STROKE_SCALE_MAX,
14	  SECTION_VIEWPORT_STROKE_SCALE_MIN,
15	  SECTION_VIEWPORT_U_SPAN_BRACKET_MARGIN_PX,
16	  SECTION_VIEWPORT_U_SPAN_LABEL_MIN_PX,
17	  SECTION_VIEWPORT_WALL_HATCH_ALONG_CUT_TILE,
18	  SECTION_VIEWPORT_WALL_HATCH_ALONG_STROKE_FACTOR,
19	  SECTION_VIEWPORT_WALL_HATCH_EDGE_ON_TILE,
20	} from '../plan/symbology';
21	import {
22	  formatSectionAlongCutSpanMmLabel,
23	  formatSectionDocMaterialHintCaption,
24	  formatSectionElevationSpanMmLabel,
25	  formatSectionLevelDatumCaption,
26	  formatSectionSheetCalloutsLabel,
27	  formatSectionStairDocumentationCaption,
28	  formatSectionWallHatchReadout,
29	  parseSectionWallCutHatchKind,
30	  summarizeWallCutHatchKinds,
31	  type SectionDocMaterialHint,
32	  type SectionSheetCalloutRow,
33	  type SectionWallHatchSummary,
34	} from './sectionViewportDoc';
35	
36	type UzPrim = {
37	  uStartMm: number;
38	  uEndMm: number;
39	  zBottomMm: number;
40	  zTopMm: number;
41	};
42	
43	type OpeningPrim = UzPrim & { id: string };
44	
45	type RoofPrim = {
46	  uStartMm: number;
47	  uEndMm: number;
48	  zMm: number;
49	};
50	
51	type LevelMarkerPrim = {
52	  id: string;
53	  name: string;
54	  elevationMm: number;
55	};
56	
57	const MM_EPS = 0.5;
58	
59	function formatElevationMmLabel(mm: number): string {
60	  return `${(mm / 1000).toFixed(2)} m`;
61	}
62	
63	function sectionAdvisoryFromPayload(payload: Record<string, unknown>): string | null {
64	  const raw = payload.warnings;
65	  if (!Array.isArray(raw) || raw.length === 0) return null;
66	  const sym = raw.find(
67	    (w): w is { code?: string; message?: string } =>
68	      typeof w === 'object' && w !== null && (w as { code?: string }).code === 'symmetricCropBand',
69	  );
70	  const msg =
71	    (sym?.message && String(sym.message)) ||
72	    raw
73	      .map((w) =>
74	        typeof w === 'object' && w !== null && 'message' in w
75	          ? String((w as { message?: unknown }).message ?? '')
76	          : '',
77	      )
78	      .filter(Boolean)
79	      .join(' · ');
80	  if (!msg) return null;
81	  const t = msg.trim();
82	  if (t.length <= SECTION_VIEWPORT_ADVISORY_MAX_CHARS) return t;
83	  return `${t.slice(0, SECTION_VIEWPORT_ADVISORY_MAX_CHARS - 1)}…`;
84	}
85	
86	function viewportDocScale(widthPx: number, heightPx: number): number {
87	  return Math.min(widthPx, heightPx) / SECTION_VIEWPORT_SCALE_BASELINE_PX;
88	}
89	
90	function clampedStrokeScale(widthPx: number, heightPx: number): number {
91	  const s = viewportDocScale(widthPx, heightPx);
92	  return Math.min(
93	    SECTION_VIEWPORT_STROKE_SCALE_MAX,
94	    Math.max(SECTION_VIEWPORT_STROKE_SCALE_MIN, s),
95	  );
96	}
97	
98	function labelFontPx(widthPx: number, heightPx: number): number {
99	  const strokeScale = clampedStrokeScale(widthPx, heightPx);
100	  const base = 11 * strokeScale;
101	  return Math.min(
102	    SECTION_VIEWPORT_LABEL_FONT_MAX_PX,
103	    Math.max(SECTION_VIEWPORT_LABEL_FONT_MIN_PX, base),
104	  );
105	}
106	
107	/** Build pixel-space SVG paths/shapes from `sectionProjectionPrimitives_v1`. */
108	export function SectionViewportSvg(props: {
109	  modelId: string;
110	  sectionCutId: string;
111	  widthPx: number;
112	  heightPx: number;
113	  /** Optional single-line identity (e.g. from `formatSectionCutIdentityLine`). */
114	  sectionIdentityCaption?: string;
115	  /** Optional cut-line / view-heading line (e.g. from `formatSectionCutPlaneContext`). */
116	  sectionCutPlaneCaption?: string;
117	  /** Fires after projection resolves; `false` when there are no wall primitives (empty framing). */
118	  onWallPrimitivesKnown?: (hasWalls: boolean) => void;
119	}) {
120	  const [err, setErr] = useState<string | null>(null);
121	
122	  type LayerSnap = {
123	    wallPathsEdgeOn: string[];
124	    wallPathsAlongCut: string[];
125	    floorPaths: string[];
126	    roomPaths: string[];
127	    stairPaths: string[];
128	    roofLines: RoofPrim[];
129	    doors: OpeningPrim[];
130	    windows: OpeningPrim[];
131	    u0: number;
132	    z0: number;
133	    z1: number;
134	    du: number;
135	    dz: number;
136	    sx: number;
137	    sy: number;
138	    levelMarkers: LevelMarkerPrim[];
139	    advisory: string | null;
140	    calloutsCaption: string | null;
141	    sectionGeomExtent: { uMinMm: number; uMaxMm: number } | null;
142	    materialHints: SectionDocMaterialHint[];
143	    wallHatchSummary: SectionWallHatchSummary;
144	    levelMarkersTotalFromServer: number;
145	    stairDocCaption: string | null;
146	  };
147	
148	  const [layers, setLayers] = useState<LayerSnap | null>(null);
149	
150	  const defsId = useMemo(
151	    () => `sec-hatch-${props.sectionCutId.replace(/[^\w]/g, '')}`,
152	    [props.sectionCutId],
153	  );
154	
155	  const strokeScale = clampedStrokeScale(props.widthPx, props.heightPx);
156	  const lvlPx = labelFontPx(props.widthPx, props.heightPx);
157	  const openingTagMinPx = SECTION_VIEWPORT_OPENING_TAG_MIN_PX;
158	  const materialHintMinPx = SECTION_VIEWPORT_MATERIAL_HINT_MIN_VIEW_PX;
159	  const borderStroke = 3 * strokeScale;
160	  const patternWallLineEdgeOn = 3.5 * strokeScale;
161	  const patternWallLineAlongCut =
162	    patternWallLineEdgeOn * SECTION_VIEWPORT_WALL_HATCH_ALONG_STROKE_FACTOR;
163	  const patternSlabStroke = 1.25 * strokeScale;
164	  const floorStroke = 2.25 * strokeScale;
165	  const stairStroke = 2 * strokeScale;
166	  const datumStroke = 1.5 * strokeScale;
167	  const levelLineStroke = 1.1 * strokeScale;
168	  const wallStroke = 3 * strokeScale;
169	  const roofStroke = 3 * strokeScale;
170	  const winStroke = 1 * strokeScale;
171	  const doorStroke = 1.75 * strokeScale;
172	
173	  const onWallPrimitivesKnownRef = useRef(props.onWallPrimitivesKnown);
174	  onWallPrimitivesKnownRef.current = props.onWallPrimitivesKnown;
175	
176	  useEffect(() => {
177	    let cancel = false;
178	    void (async () => {
179	      try {
180	        const payload = (await fetchSectionProjectionWire(
181	          props.modelId,
182	          props.sectionCutId,
183	        )) as Record<string, unknown>;
184	        const advisory = sectionAdvisoryFromPayload(payload);
185	        const prim = payload.primitives as Record<string, unknown> | undefined;
186	        const wallsRaw = prim?.walls;
187	        if (!Array.isArray(wallsRaw) || wallsRaw.length === 0) {
188	          if (!cancel) {
189	            setErr(null);
190	            setLayers(null);
191	            onWallPrimitivesKnownRef.current?.(false);
192	          }
193	          return;
194	        }
195	
196	        const wallHatchSummary = summarizeWallCutHatchKinds(
197	          wallsRaw as ReadonlyArray<{ cutHatchKind?: string }>,
198	        );
199	
200	        const levelMarkersRaw = prim?.levelMarkers;
201	        const allLevelMarkers: LevelMarkerPrim[] = [];
202	        if (Array.isArray(levelMarkersRaw)) {
203	          for (const m of levelMarkersRaw as Record<string, unknown>[]) {
204	            allLevelMarkers.push({
205	              id: String(m.id ?? ''),
206	              name: String(m.name ?? m.id ?? ''),
207	              elevationMm: Number(m.elevationMm ?? 0),
208	            });
209	          }
210	        }
211	        allLevelMarkers.sort((a, b) => {
212	          if (a.elevationMm !== b.elevationMm) return a.elevationMm - b.elevationMm;
213	          return a.id.localeCompare(b.id);
214	        });
215	        const levelMarkersTotalFromServer = allLevelMarkers.length;
216	
217	        const sheetCalloutsRaw = prim?.sheetCallouts;
218	        const sheetCalloutRows: SectionSheetCalloutRow[] = [];
219	        if (Array.isArray(sheetCalloutsRaw)) {
220	          for (const row of sheetCalloutsRaw) {
221	            if (typeof row !== 'object' || row === null) continue;
222	            const o = row as Record<string, unknown>;
223	            const sid = String(o.id ?? '').trim();
224	            if (!sid) continue;
225	            sheetCalloutRows.push({ id: sid, name: String(o.name ?? sid) });
226	          }
227	        }
228	        const calloutsCaption =
229	          sheetCalloutRows.length > 0 ? formatSectionSheetCalloutsLabel(sheetCalloutRows) : null;
230	
231	        const geomRaw = prim?.sectionGeometryExtentMm;
232	        let sectionGeomExtent: { uMinMm: number; uMaxMm: number } | null = null;
233	        if (typeof geomRaw === 'object' && geomRaw !== null) {
234	          const o = geomRaw as Record<string, unknown>;
235	          const gu0 = Number(o.uMinMm);
236	          const gu1 = Number(o.uMaxMm);
237	          if (Number.isFinite(gu0) && Number.isFinite(gu1) && Math.abs(gu1 - gu0) > MM_EPS) {
238	            sectionGeomExtent = { uMinMm: gu0, uMaxMm: gu1 };
239	          }
240	        }
241	
242	        const mhRaw = prim?.sectionDocMaterialHints;
243	        const materialHints: SectionDocMaterialHint[] = [];
244	        if (Array.isArray(mhRaw)) {
245	          for (const row of mhRaw as Record<string, unknown>[]) {
246	            if (typeof row !== 'object' || row === null) continue;
247	            const o = row as Record<string, unknown>;
248	            const tid = String(o.tokenId ?? '').trim();
249	            if (!tid) continue;
250	            materialHints.push({
251	              tokenId: tid,
252	              wallElementId: String(o.wallElementId ?? ''),
253	              materialLabel: String(o.materialLabel ?? ''),
254	              cutPatternHint: parseSectionWallCutHatchKind(o.cutPatternHint),
255	              uAnchorMm: Number(o.uAnchorMm ?? 0),
256	              zAnchorMm: Number(o.zAnchorMm ?? 0),
257	            });
258	          }
259	        }
260	        materialHints.sort((a, b) => a.tokenId.localeCompare(b.tokenId));
261	
262	        const asUz = (w: Record<string, unknown>): UzPrim | null => ({
263	          uStartMm: Number(w.uStartMm ?? 0),
264	          uEndMm: Number(w.uEndMm ?? 0),
265	          zBottomMm: Number(w.zBottomMm ?? 0),
266	          zTopMm: Number(w.zTopMm ?? 0),
267	        });
268	
269	        const wallRectsEdgeOn: UzPrim[] = [];
270	        const wallRectsAlongCut: UzPrim[] = [];
271	        for (const w of wallsRaw as Record<string, unknown>[]) {
272	          const p = asUz(w);
273	          if (!p) continue;
274	          const kind = parseSectionWallCutHatchKind(w.cutHatchKind);
275	          if (kind === 'edgeOn') wallRectsEdgeOn.push(p);
276	          else wallRectsAlongCut.push(p);
277	        }
278	
279	        const floorRects: UzPrim[] = [];
280	        const floorsRaw = prim?.floors;
281	        if (Array.isArray(floorsRaw)) {
282	          for (const w of floorsRaw as Record<string, unknown>[]) {
283	            const p = asUz(w);
284	            if (p) floorRects.push(p);
285	          }
286	        }
287	
288	        const roomRects: UzPrim[] = [];
289	        const roomsRaw = prim?.rooms;
290	        if (Array.isArray(roomsRaw)) {
291	          for (const w of roomsRaw as Record<string, unknown>[]) {
292	            const p = asUz(w);
293	            if (p) roomRects.push(p);
294	          }
295	        }
296	
297	        const stairRects: UzPrim[] = [];
298	        const stairDocSource: Record<string, unknown>[] = [];
299	        const stairsRaw = prim?.stairs;
300	        if (Array.isArray(stairsRaw)) {
301	          for (const w of stairsRaw as Record<string, unknown>[]) {
302	            stairDocSource.push(w);
303	            const p = asUz(w);
304	            if (!p) continue;
305	            const halfU =
306	              Number.isFinite(Number(w.widthMm)) && Number(w.widthMm) > 0
307	                ? Math.abs(Number(w.widthMm)) / 2
308	                : 0;
309	            const uLo = Math.min(p.uStartMm, p.uEndMm) - halfU;
310	            const uHi = Math.max(p.uStartMm, p.uEndMm) + halfU;
311	            stairRects.push({ ...p, uStartMm: uLo, uEndMm: uHi });
312	          }
313	        }
314	        const stairDocCaption = formatSectionStairDocumentationCaption(stairDocSource);
315	
316	        const roofLines: RoofPrim[] = [];
317	        const roofsRaw = prim?.roofs;
318	        if (Array.isArray(roofsRaw)) {
319	          for (const w of roofsRaw as Record<string, unknown>[]) {
320	            roofLines.push({
321	              uStartMm: Number(w.uStartMm ?? 0),
322	              uEndMm: Number(w.uEndMm ?? 0),
323	              zMm: Number(w.zMidMm ?? w.z_mid_mm ?? w.zMm ?? 0),
324	            });
325	          }
326	        }
327	
328	        let u0 = Infinity;
329	        let u1 = -Infinity;
330	        let z0 = Infinity;
331	        let z1 = -Infinity;
332	
333	        const widen = (...arr: UzPrim[]) => {
334	          for (const r of arr) {
335	            u0 = Math.min(u0, r.uStartMm, r.uEndMm);
336	            u1 = Math.max(u1, r.uStartMm, r.uEndMm);
337	            z0 = Math.min(z0, r.zBottomMm, r.zTopMm);
338	            z1 = Math.max(z1, r.zBottomMm, r.zTopMm);
339	          }
340	        };
341	
342	        widen(...wallRectsEdgeOn, ...wallRectsAlongCut);
343	        widen(...floorRects);
344	        widen(...roomRects);
345	        widen(...stairRects);
346	
347	        for (const r of roofLines) {
348	          u0 = Math.min(u0, r.uStartMm, r.uEndMm);
349	          u1 = Math.max(u1, r.uStartMm, r.uEndMm);
350	          z0 = Math.min(z0, r.zMm);
351	          z1 = Math.max(z1, r.zMm);
352	        }
353	
354	        const doorsOpen: OpeningPrim[] = [];
355	        const doorsRaw = prim?.doors;
356	        if (Array.isArray(doorsRaw)) {
357	          for (const w of doorsRaw as Record<string, unknown>[]) {
358	            const uC = Number(w.uCenterMm ?? 0);
359	            const half = Number(w.openingHalfWidthAlongUMm ?? 0);
360	            const zb = Number(w.zBottomMm ?? 0);
361	            const zt = Number(w.zTopMm ?? 0);
362	            doorsOpen.push({
363	              id: String(w.id ?? 'door'),
364	              uStartMm: uC - Math.abs(half),
365	              uEndMm: uC + Math.abs(half),
366	              zBottomMm: zb,
367	              zTopMm: zt,
368	            });
369	            u0 = Math.min(u0, doorsOpen.at(-1)!.uStartMm);
370	            u1 = Math.max(u1, doorsOpen.at(-1)!.uEndMm);
371	            z0 = Math.min(z0, zb, zt);
372	            z1 = Math.max(z1, zb, zt);
373	          }
374	        }
375	
376	        const windowsOpen: OpeningPrim[] = [];
377	        const windowsRaw = prim?.windows;
378	        if (Array.isArray(windowsRaw)) {
379	          for (const w of windowsRaw as Record<string, unknown>[]) {
380	            const uC = Number(w.uCenterMm ?? 0);
381	            const half = Number(w.openingHalfWidthAlongUMm ?? 0);
382	            const zb = Number(w.zBottomMm ?? 0);
383	            const zt = Number(w.zTopMm ?? 0);
384	            windowsOpen.push({
385	              id: String(w.id ?? 'window'),
386	              uStartMm: uC - Math.abs(half),
387	              uEndMm: uC + Math.abs(half),
388	              zBottomMm: zb,
389	              zTopMm: zt,
390	            });
391	            u0 = Math.min(u0, windowsOpen.at(-1)!.uStartMm);
392	            u1 = Math.max(u1, windowsOpen.at(-1)!.uEndMm);
393	            z0 = Math.min(z0, zb, zt);
394	            z1 = Math.max(z1, zb, zt);
395	          }
396	        }
397	
398	        const padU = Math.max(800, (u1 - u0) * 0.08);
399	        const padZ = Math.max(400, (z1 - z0) * 0.1);
400	
401	        u0 -= padU;
402	        u1 += padU;
403	        z0 -= padZ;
404	        z1 += padZ;
405	
406	        const levelMarkersInView = allLevelMarkers.filter(
407	          (m) => m.elevationMm >= z0 - MM_EPS && m.elevationMm <= z1 + MM_EPS,
408	        );
409	
410	        const du = Math.max(u1 - u0, 1);
411	        const dz = Math.max(z1 - z0, 1);
412	        const sx = props.widthPx / du;
413	        const sy = props.heightPx / dz;
414	
415	        const rectPath = (r: UzPrim) => {
416	          const x = (Math.min(r.uStartMm, r.uEndMm) - u0) * sx;
417	          const bw = Math.abs(r.uEndMm - r.uStartMm) * sx;
418	          const yTop = (z1 - Math.max(r.zBottomMm, r.zTopMm)) * sy;
419	          const h = Math.abs(r.zTopMm - r.zBottomMm) * sy;
420	          return `M ${x} ${yTop} h ${bw} v ${h} h ${-bw} Z`;
421	        };
422	
423	        const wallPathsEdgeOn = wallRectsEdgeOn.map(rectPath);
424	        const wallPathsAlongCut = wallRectsAlongCut.map(rectPath);
425	        const floorPaths = floorRects.map(rectPath);
426	        const roomPaths = roomRects.map(rectPath);
427	        const stairPaths = stairRects.map(rectPath);
428	
429	        if (!cancel) {
430	          setErr(null);
431	          onWallPrimitivesKnownRef.current?.(true);
432	          setLayers({
433	            wallPathsEdgeOn,
434	            wallPathsAlongCut,
435	            floorPaths,
436	            roomPaths,
437	            stairPaths,
438	            roofLines,
439	            doors: doorsOpen,
440	            windows: windowsOpen,
441	            u0,
442	            z0,
443	            z1,
444	            du,
445	            dz,
446	            sx,
447	            sy,
448	            levelMarkers: levelMarkersInView,
449	            advisory,
450	            calloutsCaption,
451	            sectionGeomExtent,
452	            materialHints,
453	            wallHatchSummary,
454	            levelMarkersTotalFromServer,
455	            stairDocCaption,
456	          });
457	        }
458	      } catch (e) {
459	        if (!cancel) {
460	          setErr(e instanceof Error ? e.message : String(e));
461	          setLayers(null);
462	          onWallPrimitivesKnownRef.current?.(false);
463	        }
464	      }
465	    })();
466	
467	    return () => {
468	      cancel = true;
469	    };
470	  }, [props.modelId, props.sectionCutId, props.widthPx, props.heightPx]);
471	
472	  const vb = `0 0 ${props.widthPx} ${props.heightPx}`;
473	
474	  const topDocFontPx = Math.max(8, 9 * strokeScale);
