479	      rows.push({
480	        key: 'sec-ident',
481	        text: props.sectionIdentityCaption,
482	        testId: 'section-cut-identity-caption',
483	      });
484	    }
485	    if (props.sectionCutPlaneCaption) {
486	      rows.push({
487	        key: 'sec-plane',
488	        text: props.sectionCutPlaneCaption,
489	        testId: 'section-cut-plane-caption',
490	      });
491	    }
492	    if (layers) {
493	      rows.push({
494	        key: 'wall-hatch',
495	        text: formatSectionWallHatchReadout(layers.wallHatchSummary),
496	        testId: 'section-wall-hatch-readout',
497	      });
498	      const lvl = formatSectionLevelDatumCaption({
499	        inViewCount: layers.levelMarkers.length,
500	        totalFromServer: layers.levelMarkersTotalFromServer,
501	      });
502	      if (lvl) {
503	        rows.push({ key: 'lvl-datum', text: lvl, testId: 'section-level-datum-caption' });
504	      }
505	      if (layers.stairDocCaption) {
506	        rows.push({
507	          key: 'stair-doc',
508	          text: layers.stairDocCaption,
509	          testId: 'section-stair-doc-caption',
510	        });
511	      }
512	    }
513	    return rows;
514	  }, [layers, props.sectionCutPlaneCaption, props.sectionIdentityCaption]);
515	
516	  const roofChordPath = layers
517	    ? layers.roofLines.map((r) => {
518	        const x0 = (Math.min(r.uStartMm, r.uEndMm) - layers.u0) * layers.sx;
519	        const x1 = (Math.max(r.uStartMm, r.uEndMm) - layers.u0) * layers.sx;
520	        const y = (layers.z1 - r.zMm) * layers.sy;
